   const BigInt u1 = m_group.multiply_mod_order(e, w);
   const BigInt u2 = m_group.multiply_mod_order(r, w);
   const PointGFp R = m_gy_mul.multi_exp(u1, u2);
   if(R.is_zero())
      return false;
   const BigInt v = m_group.mod_order(R.get_affine_x());
   return (v == r);
   }

